                return reduced.optimize(session);
            }
        }
        Expression e = optimizeIfConstant(session, andOrType, left, right);
        if (e == null) {
            return optimizeN(this);
        }
        if (e instanceof ConditionAndOr) {
            return optimizeN((ConditionAndOr) e);
        }
        return e;
    }


